function buildTestSiweMessage(fields = {}) {
  const domain = String(fields.domain || '').trim();
  const address = String(fields.address || '').trim();
  const statement = String(fields.statement || '').trim();
  const uri = String(fields.uri || '').trim();
  const version = String(fields.version || '1').trim() || '1';
  const chainId = Number(fields.chainId);
  const nonce = String(fields.nonce || '').trim();
  const issuedAt = String(fields.issuedAt || '').trim();
  const expirationTime = String(fields.expirationTime || '').trim();

  const lines = [
    `${domain} wants you to sign in with your Ethereum account:`,
    address,
    '',
  ];

  if (statement) {
    lines.push(statement, '');
  }

  lines.push(
    `URI: ${uri}`,
    `Version: ${version}`,
    `Chain ID: ${chainId}`,
    `Nonce: ${nonce}`,
    `Issued At: ${issuedAt}`
  );

  if (expirationTime) {
    lines.push(`Expiration Time: ${expirationTime}`);
  }

  return lines.join('\n');
}

function authJsonRequest(pathname, method, body, headers = {}) {
  const requestHeaders = new Headers(headers);
  if (body !== undefined) {
    requestHeaders.set('Content-Type', 'application/json');
  }
  return new Request(`https://bitbi.ai${pathname}`, {
    method,
    headers: requestHeaders,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  });
}

function buildOpenClawSignedRequest(body, {
  secret = OPENCLAW_TEST_SECRET,
  agent = 'openclaw-mac',
  timestamp = new Date().toISOString(),
  nonce = randomBytes(16).toString('hex'),
  pathOverride = '/api/openclaw/news-pulse/ingest',
  methodOverride = 'POST',
  signatureOverride = null,
  rawBodyOverride = null,
  headers = {},
} = {}) {
  const rawBody = rawBodyOverride ?? (typeof body === 'string' ? body : JSON.stringify(body));
  const bodyHash = createHash('sha256').update(rawBody).digest('hex');
  const canonical = [
    methodOverride,
    pathOverride,
    timestamp,
    nonce,
    bodyHash,
  ].join('\n');
  const signature = signatureOverride || createHmac('sha256', secret).update(canonical).digest('hex');
  const requestHeaders = new Headers({
    'content-type': 'application/json',
    'cf-connecting-ip': '203.0.113.44',
    'x-openclaw-agent': agent,
    'x-openclaw-timestamp': timestamp,
    'x-openclaw-nonce': nonce,
    'x-openclaw-signature': `sha256=${signature}`,
    ...headers,
  });
  return {
    request: new Request('https://bitbi.ai/api/openclaw/news-pulse/ingest', {
      method: 'POST',
      headers: requestHeaders,
      body: rawBody,
    }),
    rawBody,
    nonce,
    signature,
    bodyHash,
  };
}

