function createAiLabRunStub() {
  return async (modelId, payload) => {
    if (
      modelId === '@cf/black-forest-labs/flux-1-schnell' ||
      modelId === '@cf/black-forest-labs/flux-2-klein-9b' ||
      modelId === '@cf/black-forest-labs/flux-2-dev'
    ) {
      return `data:image/png;base64,${ONE_PIXEL_PNG_DATA_URI.replace('data:image/png;base64,', '')}`;
    }

    if (modelId === 'openai/gpt-image-2') {
      return {
        state: 'Completed',
        result: {
          image: ONE_PIXEL_PNG_DATA_URI,
        },
        gatewayMetadata: {
          keySource: 'Unified',
        },
      };
    }

    if (
      modelId === '@cf/baai/bge-m3' ||
      modelId === '@cf/google/embeddinggemma-300m'
    ) {
      const input = Array.isArray(payload.text) ? payload.text : [payload.text];
      return {
        data: input.map((_, index) => ({
          embedding: [0.1 + index, 0.2 + index, 0.3 + index, 0.4 + index],
        })),
        shape: [input.length, 4],
        pooling: 'cls',
      };
    }

    if (modelId === 'minimax/music-2.6') {
      return {
        data: {
          audio: '494433040000000000',
          status: 2,
        },
        trace_id: 'stub-music-trace',
        extra_info: {
          music_duration: 24000,
          music_sample_rate: 44100,
          music_channel: 2,
          bitrate: 256000,
          music_size: 4096,
        },
      };
    }

    if (modelId === '@cf/google/gemma-4-26b-a4b-it' && payload.stream) {
      const sseBody = 'data: {"response":"Live "}\n\ndata: {"response":"agent "}\n\ndata: {"response":"response."}\n\ndata: [DONE]\n\n';
      return new ReadableStream({
        start(controller) {
          controller.enqueue(new TextEncoder().encode(sseBody));
          controller.close();
        },
      });
    }

    return {
      response: `Stubbed output for ${modelId}`,
      usage: {
        prompt_tokens: 12,
        completion_tokens: 18,
        total_tokens: 30,
      },
    };
  };
}

function createAiLabServiceBinding(aiWorker, aiEnv, observedRequests = null) {
  return {
    async fetch(request) {
      if (Array.isArray(observedRequests)) {
        let body = null;
        try {
          body = request.method === 'POST' ? await request.clone().json() : null;
        } catch {
          body = null;
        }
        observedRequests.push({
          url: request.url,
          method: request.method,
          correlationId: request.headers.get('x-bitbi-correlation-id'),
          serviceTimestamp: request.headers.get('x-bitbi-service-timestamp'),
          serviceNonce: request.headers.get('x-bitbi-service-nonce'),
          serviceSignature: request.headers.get('x-bitbi-service-signature'),
          body,
        });
      }
      return aiWorker.fetch(request, aiEnv, createExecutionContext().execCtx);
    },
  };
}

function createAiVideoJobServiceBinding(handler = null) {
  const calls = [];
  return {
    calls,
    binding: {
      async fetch(request) {
        let body = null;
        try {
          body = request.method === 'POST' ? await request.clone().json() : null;
        } catch {
          body = null;
        }
        calls.push({
          url: request.url,
          method: request.method,
          correlationId: request.headers.get('x-bitbi-correlation-id'),
          serviceTimestamp: request.headers.get('x-bitbi-service-timestamp'),
          serviceNonce: request.headers.get('x-bitbi-service-nonce'),
          serviceSignature: request.headers.get('x-bitbi-service-signature'),
          body,
        });
        const result = handler
          ? await handler({ request, body, calls })
          : {
              status: 200,
              body: {
                ok: true,
                result: {
                  status: 'succeeded',
                  videoUrl: 'https://cdn.example.com/generated-video.mp4',
                  posterUrl: 'https://cdn.example.com/generated-video-poster.webp',
                  providerTaskId: 'provider-task-default',
                  providerState: 'success',
                },
              },
            };
        return new Response(JSON.stringify(result.body), {
          status: result.status || 200,
          headers: { 'content-type': 'application/json; charset=utf-8' },
        });
      },
    },
  };
}

async function signedInternalAiJsonRequest(pathname, body, {
  secret = 'test-ai-service-auth-secret',
  method = 'POST',
  headers = {},
} = {}) {
  const { buildServiceAuthHeaders } = await loadServiceAuthModule();
  const bodyText = body === undefined ? '' : JSON.stringify(body);
  const serviceHeaders = await buildServiceAuthHeaders({
    secret,
    method,
    path: pathname,
    body: bodyText,
  });
  return new Request(`https://bitbi-ai.internal${pathname}`, {
    method,
    headers: {
      ...(body === undefined ? {} : { 'content-type': 'application/json' }),
      ...headers,
      ...serviceHeaders,
    },
    body: body === undefined ? undefined : bodyText,
  });
}

function createVideoAssetFetchStub(overrides = {}) {
  const calls = [];
  const fetchStub = async (url) => {
    calls.push(String(url));
    if (overrides[String(url)]) {
      return overrides[String(url)]();
    }
    if (String(url).endsWith('.webp')) {
      return new Response(new Uint8Array([9, 8, 7]), {
        status: 200,
        headers: { 'content-type': 'image/webp', 'content-length': '3' },
      });
    }
    return new Response(new Uint8Array([1, 2, 3, 4]), {
      status: 200,
      headers: { 'content-type': 'video/mp4', 'content-length': '4' },
    });
  };
  fetchStub.calls = calls;
  return fetchStub;
}

async function createAdminAiContractHarness(options = {}) {
  const authWorker = await loadWorker('workers/auth/src/index.js');
  const aiWorker = await loadWorker('workers/ai/src/index.js');
  const user = options.user || createAdminUser();
  const aiRun = options.aiRun || createAiLabRunStub();
  const aiLabRequests = [];
  let currentAiGatewayLogId = null;
  const gatewayGetLogCalls = [];
  const env = createAuthTestEnv({
    users: [user],
    imagesBinding: options.imagesBinding,
    ALLOW_SYNC_VIDEO_DEBUG: options.ALLOW_SYNC_VIDEO_DEBUG === undefined
      ? 'true'
      : options.ALLOW_SYNC_VIDEO_DEBUG,
    ...(options.authEnv || {}),
  });
  const aiEnvOverrides = options.aiEnv && typeof options.aiEnv === 'object' ? options.aiEnv : {};
  const { AI: _ignoredAiEnvOverride, ...safeAiEnvOverrides } = aiEnvOverrides;
  env.AI_LAB = createAiLabServiceBinding(aiWorker, {
    AI_SERVICE_AUTH_SECRET: env.AI_SERVICE_AUTH_SECRET,
    SERVICE_AUTH_REPLAY: options.serviceAuthReplay || new MockDurableRateLimiterNamespace(),
    ...safeAiEnvOverrides,
    AI: {
      get aiGatewayLogId() {
        return currentAiGatewayLogId;
      },
      gateway(name) {
        return {
          async getLog(logId) {
            gatewayGetLogCalls.push({ name, logId });
            if (typeof options.gatewayGetLog === 'function') {
              return options.gatewayGetLog(logId, name);
            }
            return null;
          },
        };
      },
      async run(...args) {
        let result;
        let error = null;
        try {
          result = await aiRun(...args);
          return result;
        } catch (err) {
          error = err;
          throw err;
        } finally {
          if (options.aiGatewayLogId !== undefined) {
            currentAiGatewayLogId = typeof options.aiGatewayLogId === 'function'
              ? options.aiGatewayLogId({ args, result, error })
              : options.aiGatewayLogId;
          } else {
            currentAiGatewayLogId = null;
          }
        }
      },
    },
  }, aiLabRequests);

  const authHeaders = {
    Origin: 'https://bitbi.ai',
    'CF-Connecting-IP': '203.0.113.25',
  };
  if (options.withSession !== false) {
    const token = await seedSession(env, user.id);
    authHeaders.Cookie = `bitbi_session=${token}`;
  }

  return {
    authWorker,
    env,
    authHeaders,
    user,
    gatewayGetLogCalls,
    aiLabRequests,
  };
}

const ADMIN_AI_CHARGE_ORG_ID = 'org_bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb';

function seedAdminImageChargeOrg(env, {
  orgId = ADMIN_AI_CHARGE_ORG_ID,
  creditBalance = 100,
  createdByUserId = 'admin-ai-user',
} = {}) {
  const createdAt = '2026-04-29T09:00:00.000Z';
  if (!env.DB.state.organizations.some((row) => row.id === orgId)) {
    env.DB.state.organizations.push({
      id: orgId,
      name: 'Admin Image Billing Org',
      slug: 'admin-image-billing-org',
      status: 'active',
      created_by_user_id: createdByUserId,
      created_at: createdAt,
      updated_at: createdAt,
    });
  }
  if (creditBalance > 0 && !env.DB.state.creditLedger.some((row) => row.id === `cl_admin_image_seed_${orgId}`)) {
    env.DB.state.creditLedger.push({
      id: `cl_admin_image_seed_${orgId}`,
      organization_id: orgId,
      amount: creditBalance,
      balance_after: creditBalance,
      entry_type: 'grant',
      feature_key: null,
      source: 'test_admin_image_seed',
      idempotency_key: `admin-image-seed-${orgId}`,
      request_hash: 'seed',
      created_by_user_id: createdByUserId,
      created_at: createdAt,
      metadata_json: '{}',
    });
  }
  return orgId;
}

