function captureDiagnosticLogs() {
  const entries = [];
  const originalConsole = {
    log: console.log,
    warn: console.warn,
    error: console.error,
  };

  const capture = () => (...args) => {
    for (const arg of args) {
      if (typeof arg !== 'string') continue;
      try {
        const parsed = JSON.parse(arg);
        if (parsed && typeof parsed === 'object' && typeof parsed.event === 'string') {
          entries.push(parsed);
        }
      } catch {
        // ignore non-JSON console output
      }
    }
  };

  console.log = capture();
  console.warn = capture();
  console.error = capture();

  return {
    entries,
    restore() {
      console.log = originalConsole.log;
      console.warn = originalConsole.warn;
      console.error = originalConsole.error;
    },
  };
}

function findDiagnosticEvent(entries, eventName) {
  return entries.find((entry) => entry.event === eventName) || null;
}

function parseJsonLines(body) {
  return String(body || '')
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line));
}

function parseSessionCookie(setCookie) {
  return setCookie.split(';')[0];
}

function findSetCookieValue(setCookieHeader, cookieName) {
  const match = String(setCookieHeader || '').match(new RegExp(`${cookieName}=([^;]+)`));
  return match ? `${cookieName}=${match[1]}` : null;
}

async function enrollAdminMfa({ authWorker, env, sessionCookie, userId }) {
  const { generateTotpCode } = await loadAdminMfaModule();
  const setupRes = await authWorker.fetch(
    authJsonRequest('/api/admin/mfa/setup', 'POST', {}, {
      Origin: 'https://bitbi.ai',
      Cookie: sessionCookie,
    }),
    env,
    createExecutionContext().execCtx
  );
  expect(setupRes.status).toBe(200);
  const setupBody = await setupRes.json();
  const code = await generateTotpCode(setupBody.setup.secret);
  const enableRes = await authWorker.fetch(
    authJsonRequest('/api/admin/mfa/enable', 'POST', { code }, {
      Origin: 'https://bitbi.ai',
      Cookie: sessionCookie,
    }),
    env,
    createExecutionContext().execCtx
  );
  expect(enableRes.status).toBe(200);
  const enableBody = await enableRes.json();
  const mfaCookie = findSetCookieValue(enableRes.headers.get('set-cookie'), '__Host-bitbi_admin_mfa');
  expect(mfaCookie).toBeTruthy();
  return {
    setupBody,
    enableBody,
    mfaCookie,
    recoveryCodes: setupBody.setup.recoveryCodes,
    userId,
  };
}

function findRunCalls(db, query) {
  return (db?.runCalls || []).filter((entry) => entry.query === query);
}

const SESSION_TOUCH_QUERY = 'UPDATE sessions SET last_seen_at = ? WHERE id = ? AND (last_seen_at IS NULL OR last_seen_at < ?)';
const QUOTA_READ_CLEANUP_QUERY = "DELETE FROM ai_daily_quota_usage WHERE user_id = ? AND day_start = ? AND status = 'reserved' AND expires_at < ?";

async function createSignedWalletPayload({ challenge, privateKey }) {
  const { privateKeyToAccount } = await loadWalletTestModules();
  const account = privateKeyToAccount(privateKey);
  const message = buildTestSiweMessage({
    ...challenge,
    address: account.address,
  });
  const signature = await account.signMessage({ message });
  return {
    account,
    message,
    signature,
  };
}

