  test('paid subscription invoice webhook is idempotent and tops up subscription credits only', async () => {
    const { handleVerifiedStripeLiveWebhookEvent } = await loadStripeBillingModule();
    const env = seedBucketedMember({
      userId: 'member-subscription-webhook',
      subscriptionCredits: 2000,
      legacyOrBonusCredits: 300,
      purchasedCredits: 4000,
    });
    env.STRIPE_LIVE_SUBSCRIPTION_PRICE_ID = 'price_member_pro_123456';
    const payload = {
      id: 'evt_member_subscription_invoice_paid',
      object: 'event',
      type: 'invoice.paid',
      livemode: true,
      data: {
        object: {
          id: 'in_member_subscription_invoice_paid',
          object: 'invoice',
          livemode: true,
          status: 'paid',
          customer: 'cus_member_pro_123456',
          lines: {
            data: [{
              pricing: {
                price_details: {
                  price: 'price_member_pro_123456',
                  product: 'prod_member_pro_123456',
                },
              },
              parent: {
                subscription_item_details: {
                  subscription: 'sub_member_pro_123456',
                },
              },
              period: { start: 1777593600, end: 1780272000 },
              metadata: { user_id: 'member-subscription-webhook' },
            }],
          },
          parent: {
            subscription_details: {
              subscription: 'sub_member_pro_123456',
              metadata: { user_id: 'member-subscription-webhook' },
            },
          },
        },
      },
    };
    const first = await handleVerifiedStripeLiveWebhookEvent({
      env,
      rawBody: JSON.stringify(payload),
      payload,
      verificationStatus: 'verified_test_signature',
    });
    expect(first.creditGrant).toEqual(expect.objectContaining({
      userId: 'member-subscription-webhook',
      creditsGranted: 4000,
      balanceAfter: 10300,
      subscriptionCredits: 6000,
    }));

    const ledgerCount = env.DB.state.memberCreditLedger.length;
    const paymentSucceededPayload = JSON.parse(JSON.stringify(payload));
    paymentSucceededPayload.id = 'evt_member_subscription_invoice_payment_succeeded';
    paymentSucceededPayload.type = 'invoice.payment_succeeded';
    const sameInvoiceSecondEvent = await handleVerifiedStripeLiveWebhookEvent({
      env,
      rawBody: JSON.stringify(paymentSucceededPayload),
      payload: paymentSucceededPayload,
      verificationStatus: 'verified_test_signature',
    });
    expect(sameInvoiceSecondEvent.creditGrant).toEqual(expect.objectContaining({
      userId: 'member-subscription-webhook',
      creditsGranted: 0,
      balanceAfter: 10300,
      subscriptionCredits: 6000,
      reused: true,
    }));
    expect(env.DB.state.memberCreditLedger).toHaveLength(ledgerCount);

    const duplicate = await handleVerifiedStripeLiveWebhookEvent({
      env,
      rawBody: JSON.stringify(payload),
      payload,
      verificationStatus: 'verified_test_signature',
    });
    expect(duplicate.duplicate).toBe(true);
    expect(env.DB.state.memberCreditLedger).toHaveLength(ledgerCount);
    expect(env.DB.state.memberCreditBuckets.find((row) => row.bucket_type === 'purchased').balance).toBe(4000);
    expect(env.DB.state.memberCreditBuckets.find((row) => row.bucket_type === 'legacy_or_bonus').balance).toBe(300);
  });

